import React, { useEffect, useState } from 'react'
import { Avatar, Box, Card, CardContent, CardHeader, makeStyles, Paper, Typography } from '@material-ui/core'
import Cookies from 'js-cookie'

import axios from 'axios'
import { Link } from 'react-router-dom'

const useStyle = makeStyles((theme) => {
    return {
        root: {
            '& .MuiCard-root': {
                '&:hover': {
                    transform: 'none',
                    boxShadow: '2px 5px 7px rgba(0, 0, 0, 0.25)'
                  }
            }
        },
        activityList: {
            padding: theme.spacing(1)
        },
        cardLink: {
            textDecoration: 'none',
            color: 'inherit'
        }
    }
})

export default function StudentPosts({ activity }) {
    const classes = useStyle()
    const [userWhoPosted, setUserWhoPosted] = useState('');
    const updateID = activity.userid;

    const userPosted = () => {
        const sendData = {
            updateID
        }

        axios.post('https://ursacapi.000webhostapp.com/api/getStudentID.php', JSON.stringify(sendData))
            .then(response => {
                setUserWhoPosted(response.data[0].firstName + ' ' + response.data[0].lastName)
            })
            .catch(err => console.log(err))
    }

    useEffect(() => {
        userPosted();
    }, []);

    return (
        <Box className={classes.root}>
            <Link className={classes.cardLink} to={`/studentActivity/${activity.id}`}>
                <Card className={classes.activityList} variant='outlined'>
                    <CardHeader avatar={
                        <Avatar />
                    }
                        title={userWhoPosted}
                    />
                    <CardContent>
                        <Typography variant='h6'>
                            {activity.title}
                        </Typography>
                        <Typography variant='body2'>
                            {activity.body}
                        </Typography>

                    </CardContent>
                </Card>
                <br />
            </Link>
        </Box>
    )
}
